messages.content:
CLUSTER:
[
 {
  "riskId": "risk.execution-window.compliance-serialization-zeroes-h1",
  "title": "A serialized cert-and-listing critical path zeroes H1 revenue — 'conservative ramp' is not linear in months",
  "narrative": "The YAM implicitly assumes the selling machine exists on day 1 of the 12-month window. But an intelligent PDU sold into CE must first clear a compliance stack the model only gestures at: CE (LVD/EMC), RoHS, WEEE producer registration (Germany's stiftung EAR is a named, dated gate), EORI customs registration, and the buyer-side pull-through of EU 2024/1364 (DC rating scheme, in force May 2024) and EED 2024/1791 KPI disclosures that operators now push down into vendor questionnaires. These gates are serialized — test slots before declaration, registration before listing, listing before quote. A two-quarter slip does not scale YAM by 50% linearly; it deletes the ramp's compounding front end, because the conservative ramp back-loads revenue into quarters that no longer exist.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "The real EU entry stack is materially larger than the three regimes the ledger cites: WEEE, ROHS, FCC, EORI customs, plus the 2024 DC rating scheme and EED disclosure duties landing on operators and flowing into vendor requirements",
    "refs": [
     "digest:serviceable-benchmark#c10",
     "digest:serviceable-benchmark#c8",
     "digest:serviceable-benchmark#c9"
    ]
   },
   {
    "step": "propagation",
    "text": "Each gate precedes quoting eligibility; for a pre-launch venture the qualification clock and the harvest clock are the same 12 months, so a 2-quarter serialization consumes the highest-leverage half of the obtainable window",
    "refs": [
     "profile:Stage",
     "digest:serviceable-benchmark#c6",
     "ledger:serviceableFactor"
    ]
   },
   {
    "step": "model-impact",
    "text": "Effective Year-1 obtainable share halves or worse relative to the curated 0.03, independent of demand — the market is there, the vendor is not yet legally/commercially present in it",
    "refs": [
     "ledger:obtainableFactor"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "WEEE producer-registration processing time for new foreign entrants in Germany",
    "where": "stiftung EAR (stiftung-ear.de) published processing notes and applicant guidance",
    "threshold": ">10 weeks from application to registration number",
    "updates": "increases"
   },
   {
    "signal": "Test-slot lead times for LVD/EMC certification of power distribution hardware",
    "where": "TÜV Rheinland / TÜV Nord lab booking lead-time notices to vendors",
    "threshold": ">8 weeks to first available slot",
    "updates": "increases"
   }
  ],
  "judgeTotal": 16
 },
 {
  "riskId": "risk.execution-window.firmware-audit-and-poc-attrition",
  "title": "An intelligent PDU is a networked device: the security-audit gate precedes every listing, and a third of deployed pilots never convert to accepted revenue",
  "narrative": "'Intelligent' is the product's differentiator and its hidden tax. A networked PDU with remote management enters the buyer's attack surface, so operators audit the vendor's firmware-signing, vulnerability-disclosure and update infrastructure BEFORE listing — a gate that precedes the first PO and appears nowhere in the funnel. The venture must stand up this infrastructure (secure OTA, SBOM, disclosure policy) during the same year it is supposed to harvest. And clearing the gate isn't the end: POC-stage industrial hardware shows ~30% of deployed systems never reaching acceptance — customers sign, vendors deploy, and the hardware comes back months later. Both effects hit realized Year-1 revenue after the demand, the reach, and even the PO exist, which is why no market-sizing band captures them.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "Buyer security review of networked power hardware (firmware update path, SBOM, disclosure process) is a pre-listing gate for the intelligent-PDU product class; the pre-launch venture has no audited update infrastructure on day 1",
    "refs": [
     "profile:Product",
     "profile:Stage",
     "digest:serviceable-benchmark#c12"
    ]
   },
   {
    "step": "propagation",
    "text": "Deals that clear the gate still attrit: ~30% of deployed POC-stage industrial systems are never fully accepted, so booked pilots overstate realized revenue by a large margin in the first year",
    "refs": [
     "digest:obtainable-benchmark#c8",
     "digest:obtainable-benchmark#c9"
    ]
   },
   {
    "step": "model-impact",
    "text": "Realized Year-1 obtainable share is materially below the pipeline-implied share even at constant win rates — obtainableFactor overstates what converts to accepted, invoiced revenue inside the window",
    "refs": [
     "ledger:obtainableFactor"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Cybersecurity requirements (SBOM, signed firmware, vulnerability-disclosure policy) appearing as mandatory line items in DC fit-out and rack-power RFQs",
    "where": "TED (Tenders Electronic Daily) DC procurement notices; large-operator supplier security questionnaires",
    "threshold": "Security annex mandatory in ≥half of sampled rack-power RFQs",
    "updates": "increases"
   },
   {
    "signal": "Regulatory hardening of connected-device requirements applicable to networked PDUs (RED cybersecurity delegated act enforcement; Cyber Resilience Act transition dates)",
    "where": "Official Journal of the EU / Commission standards dockets on RED 2022/30 and CRA implementation",
    "threshold": "CRA conformity dates confirmed inside the venture's Year-1 window",
    "updates": "increases"
   }
  ],
  "judgeTotal": 16
 },
 {
  "riskId": "risk.base-rate-analogy.yam-window-is-a-qualification-corridor",
  "title": "Year 1 is a certification-and-qualification corridor, not a selling year — the 3% obtainable factor silently borrows years 2–3",
  "narrative": "The obtainableFactor of 0.03 sits mid-band of generic SOM benchmarks, and it was already revised down from 6%, so it reads as conservative. But the benchmark sources themselves define SOM over a 1–3 or 3–5 year capture window, not a single year — while the entry sequence for a pre-launch CE hardware entrant is cert (6–9 months: CE/TÜV, ecodesign conformity, WEEE/EORI) followed by a 12–18 month DC hardware sales cycle. Months 1–9 of the YAM window produce zero bookable revenue by construction. Reference-class realized first-period shares (TryBuildCo's worked example ~0.1% of SAM; Tractian's ~0.001% of its market) sit one to two orders of magnitude below the 1% 'floor'. The honest Year-1 number is pilots, ≈0.5–1% of SAM, not 3%.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "A pre-launch entrant starts day 0 with no EU certifications and no installed base; the compliance artifact stack (CE, TÜV, ecodesign 2019/424 conformity, WEEE, EORI) consumes 6–9 months of the 12-month YAM window before a compliant SKU can ship",
    "refs": [
     "profile:Stage",
     "digest:serviceable-benchmark#c6",
     "digest:serviceable-benchmark#c10"
    ]
   },
   {
    "step": "propagation",
    "text": "The remaining 3–6 months cannot contain a 12–18 month enterprise/DC hardware sales cycle; the benchmark sources behind the 1–5% band explicitly define SOM as a 1–3 or 3–5 year window, so applying the mid-band to Year 1 double-counts calendar time",
    "refs": [
     "digest:obtainable-benchmark#c4",
     "digest:obtainable-benchmark#c1",
     "ledger:obtainableFactor"
    ]
   },
   {
    "step": "model-impact",
    "text": "Realized Year-1 capture is pilot revenue only; reference-class observations (worked example ~0.1% of SAM, real hardware entrant ~0.001% of market, 30% of deployed POC systems never accepted) put the honest factor at ~0.005–0.01, roughly 5x below the curated 0.03",
    "refs": [
     "digest:obtainable-benchmark#c5",
     "digest:obtainable-benchmark#c6",
     "digest:obtainable-benchmark#c8"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Certification milestone slippage vs the launch plan",
    "where": "Notified-body/TÜV test scheduling and the venture's own conformity-assessment tracker",
    "threshold": "Full compliance stack not complete by month 6 post-kickoff",
    "updates": "increases"
   },
   {
    "signal": "POC-to-PO conversion rate and elapsed cycle time on the first five pilots",
    "where": "Internal pipeline reviews / POC acceptance sign-offs at pilot accounts",
    "threshold": "Median pilot-to-PO elapsed time >6 months or acceptance rate <70%",
    "updates": "increases"
   }
  ],
  "judgeTotal": 17
 },
 {
  "riskId": "risk.competitive-foreclosure.bundling-eliminates-bakeoffs-year1",
  "title": "Incumbent power-train bundling means the standalone PDU bake-off the 3% ramp assumes rarely happens",
  "narrative": "The 3% Year-1 obtainable factor implicitly assumes the venture gets evaluated: a buyer runs a PDU selection, the venture competes, and wins its share. But the growth capacity the 9% CAGR is made of — new builds and major fit-outs — buys rack PDUs inside integrated packages from Schneider, Vertiv, Eaton and Legrand, who can price the PDU line at near-zero margin inside busway + rack + UPS + cooling bundles worth orders of magnitude more. In those deals there is no PDU bake-off to enter. The corpus's own evidence already screams this: the generic 1–5% band is contradicted by every concrete datapoint found — a worked example at ~0.1% of SAM, and a real industrial-hardware entrant (Tractian) starting at ~0.001% of its market. The 3% mid-band survived because it was framed as 'already revised down from 6%' — a conservatism that is only conservative against fantasy.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "The five to seven vendors named as market leaders (Schneider, Eaton, ABB, Legrand, Vertiv, Siemens, Tripp Lite) all sell PDUs as one line inside a ~$23B power-equipment layer of integrated DC fit-out packages, enabling near-zero-margin PDU pricing within bundles",
    "refs": [
     "digest:cr3-vendors#c6",
     "digest:cust-mix#c2",
     "ledger:shape.cr3"
    ]
   },
   {
    "step": "propagation",
    "text": "New-build and fit-out capacity — where market growth concentrates — is specified as a package, so standalone PDU evaluations exist mainly in retrofit/replacement sockets; every concrete Year-1 datapoint in the corpus (TryBuildCo ~0.1% of SAM, Tractian ~$200K against a $14.9B market) lands one to three orders of magnitude below the generic 1–5% band, and one source frames SOM as a 3–5 year window, not Year 1",
    "refs": [
     "ledger:shape.cagr",
     "digest:obtainable-benchmark#c5",
     "digest:obtainable-benchmark#c6",
     "digest:obtainable-benchmark#c4"
    ]
   },
   {
    "step": "model-impact",
    "text": "obtainableFactor 0.03 assumes access to competitive evaluations across the whole SAM; restricted to the standalone-evaluation slice with hardware-entrant win rates, the realistic Year-1 pace is ≤0.5% of SAM, cutting YAM by roughly five-sixths",
    "refs": [
     "ledger:obtainableFactor",
     "digest:obtainable-benchmark#c8"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Fraction of addressable Year-1 opportunities where rack PDUs are specified standalone vs inside an integrated fit-out package",
    "where": "CE colo/enterprise fit-out tender documents and the venture's CRM opportunity coding",
    "threshold": "<30% of qualified opportunities are standalone PDU purchases",
    "updates": "increases"
   },
   {
    "signal": "Incumbent commentary on integrated-solution attach rates and rack-system bundling",
    "where": "Vertiv and Schneider quarterly earnings calls; product-launch materials for integrated rack/power-train offerings",
    "threshold": "Explicit strategy statements on selling rack power as part of integrated systems, with PDUs positioned as an attach line",
    "updates": "increases"
   }
  ],
  "judgeTotal": 17
 },
 {
  "riskId": "risk.competitive-foreclosure.distributor-line-review-lockout",
  "title": "Annual line reviews and exclusivity terms lock the distribution channel for the launch year",
  "narrative": "The distributor cell (13%) and much of the mid/enterprise cell (25%) are reached through master distributors and reseller networks — the MaxPower model, where the distributor sells to resellers, not end customers. Those distributors run annual line reviews: category slots are allocated once a year, often with exclusivity or MDF commitments to the incumbent PDU line, and intelligent-PDU buyer guides note distributors already carry OEM/private-label options that fill the 'value' slot. A pre-launch entrant arrives mid-cycle into a category that is already filled twice over. The result is not a lower win rate — it is that the indirect channel produces zero Year-1 revenue while the model quietly assumes it contributes at the same 3% pace as everything else.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "CE power-infrastructure distribution operates on the master-distributor model with annual line reviews; category slots for rack power are held by incumbent lines and supplemented by private-label ODM options the distributor already controls",
    "refs": [
     "digest:cust-mix#c8",
     "digest:cust-mix#c13",
     "ledger:cust.distributor"
    ]
   },
   {
    "step": "propagation",
    "text": "An entrant launching mid-cycle cannot obtain a line-card slot until the next review, and no corpus source quantifies indirect share or documents off-cycle onboarding — the mid/enterprise cell that buys through these resellers is similarly delayed, pushing all distribution-routed deals beyond the 12-month window",
    "refs": [
     "profile:Stage",
     "digest:cust-mix#c4",
     "ledger:cust.operator-mid"
    ]
   },
   {
    "step": "model-impact",
    "text": "cust.distributor (0.13) is unavailable for Year 1 and the blended Year-1 pace across remaining cells falls below the 3% mid-band, because the funnel applies one obtainableFactor uniformly across channels with radically different onboarding clocks",
    "refs": [
     "ledger:cust.distributor",
     "ledger:obtainableFactor"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Rack-power category composition on published line cards of the top-5 CE power/IT-infrastructure distributors",
    "where": "Distributor line cards and published price lists (vendor pages of major CE electrical and IT distribution groups)",
    "threshold": "Category shows incumbent line + a private-label option in ≥4 of 5 line cards — both slots filled",
    "updates": "increases"
   },
   {
    "signal": "Response pattern to the venture's distribution inquiries",
    "where": "Venture's own channel-recruitment log across first 2 quarters",
    "threshold": "≥3 distributors respond 'category filled, revisit at next annual review'",
    "updates": "increases"
   }
  ],
  "judgeTotal": 16
 },
 {
  "riskId": "risk.demand-discontinuity.grid-queue-construction-pause",
  "title": "Frankfurt's 24–36-month grid queue and Amsterdam's 350 MVA cap turn the venture's 12-month window into a delivery trough",
  "narrative": "78% of the modeled TAM sits in Germany and the Netherlands — precisely the two geographies where capacity additions are grid-gated. Frankfurt (60–75% of German capacity) faces 24–36-month grid-connection waits; Amsterdam is at 852 MW with a draft zoning plan capping new connections at 350 MVA until 2030; EMEA-wide, capacity under construction has plateaued at ~2.5 GW despite a 15 GW pipeline. PDU orders land at fit-out milestones, which are gated by energization dates, not by the 9% trend CAGR. If 2026 energizations slip right — and the queue data says many will — Year-1 orders slip with them, regardless of what the market does by 2030.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "Frankfurt carries ~745 MW of IT load with grid connections facing 24–36-month waits; Amsterdam's draft umbrella zoning plan caps new connection capacity at 350 MVA until 2030; EMEA under-construction capacity has plateaued at ~2.5 GW on power and permitting constraints",
    "refs": [
     "digest:geo-DE#c20",
     "digest:geo-NL#c8",
     "digest:geo-NL#c3"
    ]
   },
   {
    "step": "propagation",
    "text": "Germany (0.50) and the Netherlands (0.28) are 78% of the geographic weight, and Frankfurt alone is 60–75% of the German base — so a grid-driven slip in these two hubs is a slip in most of the venture's addressable fit-out calendar",
    "refs": [
     "ledger:geo.DE",
     "ledger:geo.NL",
     "digest:geo-DE#c1",
     "digest:geo-DE#c4"
    ]
   },
   {
    "step": "model-impact",
    "text": "The 9% CAGR is a 2030 trend, not a 2026 delivery schedule; YAM is a first-12-months number, so the slip compiles to obtainableFactor (pace), not to the trend node — Year-1 orderable fit-outs shrink even while the long-run TAM is intact",
    "refs": [
     "ledger:shape.cagr",
     "ledger:obtainableFactor",
     "profile:Stage"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Grid-connection queue length and new-connection moratoria in the Frankfurt region",
    "where": "TenneT/Amprion grid development and connection-request disclosures; Hessen regional planning dockets",
    "threshold": "Queue quotes lengthening beyond 36 months or a formal connection pause",
    "updates": "increases"
   },
   {
    "signal": "Under-construction → live conversion rate in Amsterdam and Frankfurt",
    "where": "JLL German data center market updates; Cushman & Wakefield EMEA data centre update (H1 2026)",
    "threshold": "Live-capacity additions <15% YoY in either hub",
    "updates": "increases"
   },
   {
    "signal": "Finalization of Amsterdam's umbrella zoning plan connection cap",
    "where": "Gemeente Amsterdam zoning consultation docket; DC Byte Amsterdam market page",
    "threshold": "350 MVA cap adopted as drafted",
    "updates": "increases"
   }
  ],
  "judgeTotal": 19
 },
 {
  "riskId": "risk.regulatory-gauntlet.enefg-grid-slip-de-demand",
  "title": "EnEfG efficiency mandates plus 24–36-month Frankfurt grid queues push German new-build PDU orders past the YAM window while the snapshot TAM stays flat",
  "narrative": "PDU revenue recognizes at fit-out and energization — not at announcement. Germany's Energy Efficiency Act (EnEfG) imposes PUE ≤1.2 and waste-heat-reuse duties on data centres commencing operation from mid-2026, forcing design rework on exactly the pipeline the entrant would sell into; simultaneously Frankfurt grid connections face documented 24–36-month waits and FLAP-D prices are rising. The market data that looks like strength — record-low 6.3% vacancy, 83% pre-let pipeline — actually means replacement demand cannot compensate for slipped new-build fit-outs inside 12 months. geo.DE's 0.50 is a 2025 capacity snapshot; the Year-1 orderable German slice is smaller and slower than the funnel implies, and Germany is half the funnel.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "EnEfG PUE/waste-heat mandates bite for German DCs commencing operation from mid-2026 (with EED 2024/1791 layering KPI disclosure), while Frankfurt — ~60–75% of German capacity — faces 24–36-month grid-connection waits and 12% FLAP-D price rises in 2026",
    "refs": [
     "digest:serviceable-benchmark#c9",
     "digest:geo-DE#c20",
     "digest:geo-DE#c1"
    ]
   },
   {
    "step": "propagation",
    "text": "New-build fit-outs — the moment rack PDUs are specified and ordered — slip as designs are reworked for compliance and energization dates move right; with vacancy at a record-low 6.3% and the pipeline 83% pre-let, there is no slack inventory of halls generating near-term replacement PDU demand to offset the slip",
    "refs": [
     "digest:geo-DE#c21",
     "ledger:geo.DE"
    ]
   },
   {
    "step": "model-impact",
    "text": "The German half of the funnel is a static 2025 snapshot: the Year-1 orderable DE slice is smaller in absolute terms and converts slower than geo.DE 0.50 × obtainableFactor 0.03 implies — a timing hollow-out invisible in the level-based bands",
    "refs": [
     "ledger:geo.DE",
     "ledger:obtainableFactor"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Announced energization/commissioning slips at flagship German builds",
    "where": "JLL German data-center quarterly reports; TenneT/Amprion grid-connection announcements; operator capex calls (e.g., Vantage, NTT GDC Europe)",
    "threshold": "≥2 flagship Frankfurt/Berlin builds announcing 6+ month slips to energization",
    "updates": "increases"
   },
   {
    "signal": "EnEfG enforcement and transition-waiver practice for data centres",
    "where": "BfEE/BAFA guidance dockets; German Datacenter Association (germandatacenters.com) position papers",
    "threshold": "strict application of PUE/heat-reuse rules to 2026 commencements without transitional waivers",
    "updates": "increases"
   }
  ],
  "judgeTotal": 17
 },
 {
  "riskId": "risk.execution-window.som-window-semantics-mismatch",
  "title": "The 3% Year-1 obtainable is a 3–5-year benchmark wearing a 12-month clock",
  "narrative": "The obtainableFactor was 'triangulated' from generic SOM heuristics — but the benchmark sources themselves disagree on what period the percentage describes. Wise defines SOM as a 3–5-year capture window; Prospeo and IdeaPlan frame 1–3 years. Applied to a single pre-launch year, the same literature implies numbers an order of magnitude lower: TryBuildCo's own worked example lands at ~0.1% of SAM, and the one real industrial hardware entrant found (Tractian) started at ~$200K against a $14.9B market. The model's 0.01–0.05 band brackets the wrong quantity — it brackets a multi-year share, not a first-12-months share for a company that starts the year without certs, channel, or references.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "The benchmarks behind the 3% mid-band describe 1–3 or 3–5 year capture windows, not the first 12 months the profile specifies",
    "refs": [
     "digest:obtainable-benchmark#c1",
     "digest:obtainable-benchmark#c4",
     "profile:Stage"
    ]
   },
   {
    "step": "propagation",
    "text": "When the same sources are read at the Year-1 grain, observed and worked-example first-period shares fall to 0.1% of SAM and below — orders of magnitude under the curated band's 1% floor",
    "refs": [
     "digest:obtainable-benchmark#c5",
     "digest:obtainable-benchmark#c6",
     "digest:obtainable-benchmark#c7"
    ]
   },
   {
    "step": "model-impact",
    "text": "obtainableFactor 0.03 overstates Year-1 capture by roughly 5x; YAM scales linearly with it while TAM/SAM stay untouched",
    "refs": [
     "ledger:obtainableFactor"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Months from launch to first paid PO for new rack-power/DC-hardware entrants in EMEA",
    "where": "Press releases and case studies of recent PDU/rack-power market entrants; Data Centre Dynamics vendor-launch coverage",
    "threshold": ">9 months median to first PO",
    "updates": "increases"
   },
   {
    "signal": "Time for a new vendor to appear on CE electrical-distributor line cards after launch",
    "where": "Rexel, Sonepar and regional CE distributor published line cards / new-vendor announcements",
    "threshold": ">2 quarters to first listing",
    "updates": "increases"
   }
  ],
  "judgeTotal": 18
 },
 {
  "riskId": "risk.base-rate-analogy.fragmented-incumbency-price-response",
  "title": "Five-to-seven co-equal incumbents plus an import price floor turn every entrant win into a contested knife-fight, pinning Year-1 pace to the band floor",
  "narrative": "shape.cr3's 0.55 is extrapolated from a single 15.8% Schneider datapoint; the actual evidence shows five to seven co-equal 'leading' vendors (Schneider, Eaton, Vertiv, ABB, Legrand, Siemens, nVent) and only qualitative 'medium/semi-consolidated' labels, with 60–70% import dependence in Eastern Europe setting a low-cost price floor. That structure is worse for an entrant than a tight oligopoly: more scaled players able and motivated to price-match any pilot win inside their accounts, bundling PDUs with UPS and busway lines the entrant doesn't carry. The model prices incumbent response at exactly zero — no source quantifies it, and an unquantified competitive response is a risk, not a comfort. The reference-class outcome is win-rates and cycle times that pin Year-1 obtainable share at the 0.01 band floor rather than the 0.03 mid.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "The entrant's first competitive bids surface in a field where 5–7 scaled incumbents each defend account share, and low-cost import supply anchors the price floor in the faster-growing eastern geographies",
    "refs": [
     "digest:cr3-vendors#c5",
     "digest:cr3-vendors#c6",
     "ledger:shape.cr3"
    ]
   },
   {
    "step": "propagation",
    "text": "Incumbents respond inside accounts with framework discounts and bundle pricing (PDU + UPS + containment), stretching the entrant's win rate and cycle length; SOM guidance itself says capture is a function of win-rate and conversion, and no cached source quantifies incumbent response — the model implicitly sets it to zero",
    "refs": [
     "digest:cr3-vendors#c1",
     "digest:obtainable-benchmark#c9",
     "ledger:obtainableFactor"
    ]
   },
   {
    "step": "model-impact",
    "text": "Depressed win-rate and stretched cycles convert the same pipeline into materially less Year-1 revenue: obtainableFactor lands at the 0.01 band floor, not the 0.03 mid-band the generic benchmarks suggest",
    "refs": [
     "ledger:obtainableFactor",
     "digest:obtainable-benchmark#c0"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Targeted rebate and promo activity on incumbent intelligent-PDU lines",
    "where": "Schneider/Vertiv/Eaton distributor price lists and channel rebate programs in Germany and the Netherlands",
    "threshold": "Targeted discounts >10% on intelligent-PDU SKUs appearing after the entrant's first public wins",
    "updates": "increases"
   },
   {
    "signal": "Loss-reason distribution in competitive bids",
    "where": "The venture's CRM bid post-mortems, reviewed quarterly",
    "threshold": ">50% of losses citing incumbent price match or bundle pricing",
    "updates": "increases"
   }
  ],
  "judgeTotal": 17
 },
 {
  "riskId": "risk.regulatory-gauntlet.cra-conformity-clock",
  "title": "Cyber Resilience Act's Sept-2026 reporting and Dec-2027 conformity deadlines turn Year-1 large-operator tenders into CRA-readiness screens",
  "narrative": "An intelligent, networked PDU is a product-with-digital-elements under Regulation (EU) 2024/2847. Vulnerability-reporting obligations land 11 September 2026 — inside the venture's first 12 months — and full conformity (CRA CE marking, technical file, SBOM, coordinated vulnerability disclosure) lands 11 December 2027. Sophisticated buyers do not wait for legal deadlines: large operators are already writing CRA clauses into 2026 procurement frameworks. With CRA harmonized standards not yet published and notified-body capacity scarce, a pre-launch entrant cannot close a CRA-credible technical file inside the entry window. The serviceableFactor evidence names only EN 50600, ecodesign 2019/424 and CE/TÜV — the newest and most binding instrument for THIS product class is absent from the model entirely.",
  "mechanism": [
